const { graphqlHTTP, makeExecutableSchema } = require('apollo-server-express');
const express = require('express');
const { ApolloServer, gql } = require('apollo-server');
const { Pool } = require('pg');

// Define your schema
const typeDefs = gql`
  type Author {
    id: ID!
    name: String!
  }

  type Post {
    id: ID!
    title: String!
    author: Author
  }

  type Query {
    posts: [Post]
  }
`;

// Define your resolvers
const resolvers = {
  Query: {
    posts: () => {
      return query('SELECT * FROM posts'); // Pseudo code for actual database query
    },
  },
  Post: {
    author: (post) => {
      return query(`SELECT * FROM authors WHERE id = ${post.author_id}`); // Pseudo code for actual database query
    },
  },
};

// Database connection setup
const pool = new Pool({
  user: 'your_user',
  host: 'localhost',
  database: 'your_database',
  password: 'your_password',
  port: 5432,
});

function query(sql) {
  return new Promise((resolve, reject) => {
    pool.query(sql, [], (error, results) => {
      if (error) {
        reject(error);
      } else {
        resolve(results.rows);
      }
    });
  });
}

// Initialize your GraphQL API
const schema = makeExecutableSchema({ typeDefs, resolvers });
const app = express();
const server = new ApolloServer({ schema });
server.applyMiddleware({ app });

app.listen({ port: 4000 }, () =>
  console.log(`🚀 Server ready at http://localhost:4000${server.graphqlPath}`)
);